// ❌ BAD - wrong middleware order means user identity is unknown during authz check
app.UseAuthorization();
app.UseAuthentication();

// ✅ GOOD - identity is established before permissions are evaluated
app.UseAuthentication();
app.UseAuthorization();

[Authorize(Roles = "Admin")]
public IActionResult DeleteAccount(int userId) => Ok();

// ❌ BAD - using the access token to identify the user (may be opaque or lack user claims)
var userName = ParseUserFromAccessToken(accessToken);

// ✅ GOOD - use OIDC middleware and read identity from the populated ClaimsPrincipal
builder.Services.AddAuthentication().AddOpenIdConnect(o => {
    o.Authority = "https://login.microsoftonline.com/contoso.onmicrosoft.com/v2.0";
    o.ClientId = "retail-portal-client";
    o.Scope.Add("openid");
    o.Scope.Add("email");
});
// Identity claims are then available via HttpContext.User.Claims

// ❌ BAD - implicit flow returns tokens in the URL fragment, no proof of possession
// Authorization URL: response_type=token (implicit - deprecated)

// ✅ GOOD - PKCE with Authorization Code flow in ASP.NET Core OIDC middleware
builder.Services.AddAuthentication().AddOpenIdConnect(o => {
    o.ResponseType = OpenIdConnectResponseType.Code;
    o.UsePkce = true; // true by default in .NET 8+
    o.ClientId = "retail-mobile-app";
    o.Scope.Add("openid");
    o.Scope.Add("offline_access");
});

// ❌ BAD - audience and lifetime validation disabled, accepts expired tokens for any audience
options.TokenValidationParameters = new() {
    ValidateIssuer = true,
    ValidateAudience = false,
    ValidateLifetime = false,
    ValidateIssuerSigningKey = true
};

// ✅ GOOD - all four validations enabled, audience locked to this specific API
options.TokenValidationParameters = new() {
    ValidateIssuer = true,   ValidIssuer = "https://login.contoso.com",
    ValidateAudience = true, ValidAudience = "https://api.contoso.com",
    ValidateLifetime = true,
    ValidateIssuerSigningKey = true
};

// ❌ BAD - storing JWT in localStorage exposes it to any XSS on the page
// Front-end: localStorage.setItem('token', jwtToken);

// ✅ GOOD - hybrid: short-lived JWT in memory, refresh token in HttpOnly cookie
app.MapPost("/auth/refresh", async (HttpContext ctx, ITokenService tokens) => {
    var refreshToken = ctx.Request.Cookies["refresh_token"];
    var newTokens = await tokens.RotateAsync(refreshToken);
    ctx.Response.Cookies.Append("refresh_token", newTokens.Refresh,
        new CookieOptions { HttpOnly = true, Secure = true,
                            SameSite = SameSiteMode.Strict });
    return Results.Ok(new { access_token = newTokens.Access });
});

// ❌ BAD - no rotation, no reuse detection, raw token stored in DB
public string Refresh(string token) {
    var user = _db.Users.FirstOrDefault(u => u.RefreshToken == token);
    return GenerateAccessToken(user);
}

// ✅ GOOD - rotation with reuse detection, token stored as hash
public async Task<TokenPair> RotateAsync(string incoming) {
    var stored = await _db.RefreshTokens
        .SingleOrDefaultAsync(t => t.TokenHash == Hash(incoming));
    if (stored is null || stored.IsRevoked)
        throw new SecurityException("Token reuse detected - revoking session");
    stored.IsRevoked = true;
    await _db.SaveChangesAsync();
    return await IssueNewPairAsync(stored.UserId);
}

// ❌ BAD - hardcoded role strings scattered across controllers, brittle to change
[Authorize(Roles = "HR,HRManager,HRAdmin")]
public IActionResult ViewSalaries() => Ok();

// ✅ GOOD - named policy centralises the rule and combines claims with roles
builder.Services.AddAuthorization(o => {
    o.AddPolicy("CanViewSalaries", p =>
        p.RequireRole("HRManager", "HRAdmin")
         .RequireClaim("employmentType", "permanent"));
});
[Authorize(Policy = "CanViewSalaries")]
public IActionResult ViewSalaries() => Ok();

// ❌ BAD - client secret in config, needs rotation, risks being committed to git
// "AzureAd": { "ClientSecret": "abc123xyz" }

// ✅ GOOD - Managed Identity via DefaultAzureCredential, zero stored credentials
builder.Configuration.AddAzureKeyVault(
    new Uri("https://kv-retailapp.vault.azure.net/"),
    new DefaultAzureCredential());
// In Azure: uses Managed Identity token from IMDS
// Locally: falls back to Azure CLI / Visual Studio credentials

// ❌ BAD - rolling your own user store with an insecure hash algorithm
public void Register(string email, string password) {
    var hash = MD5.HashData(Encoding.UTF8.GetBytes(password)); // MD5 is broken
    _db.Users.Add(new User { Email = email, PasswordHash = Convert.ToBase64String(hash) });
}

// ✅ GOOD - Identity handles PBKDF2 hashing with unique salt automatically
var result = await _userManager.CreateAsync(
    new ApplicationUser { Email = email, UserName = email }, password);
if (!result.Succeeded)
    return BadRequest(result.Errors);

// ❌ BAD - hour-long tokens with no revocation - a leaked token is valid for an hour
var token = new JwtSecurityToken(expires: DateTime.UtcNow.AddHours(1));

// ✅ GOOD - short-lived token + security stamp check for instant per-user revocation
services.AddAuthentication().AddJwtBearer(o => {
    o.Events = new JwtBearerEvents {
        OnTokenValidated = async ctx => {
            var userId = ctx.Principal.FindFirstValue(ClaimTypes.NameIdentifier);
            var tokenStamp = ctx.Principal.FindFirstValue("security_stamp");
            var user = await _userManager.FindByIdAsync(userId);
            var currentStamp = await _userManager.GetSecurityStampAsync(user);
            if (tokenStamp != currentStamp) ctx.Fail("Token revoked");
        }
    };
});
